data = await FileAttachment("_data/publications.json").json()
pubs = data.publications

viewof search = Inputs.text({
  label: "Search",
  placeholder: "Title, author, journal...",
  width: 400
})

viewof yearFilter = Inputs.select(
  ["All years", ...new Set(pubs.map(p =&gt; p.year).filter(Boolean).sort().reverse())],
  { label: "Year" }
)

viewof perOnly = Inputs.toggle({ label: "Physics Education Research only", value: false })

filtered = pubs.filter(p =&gt; {
  const q = search.toLowerCase()
  const matchSearch = !q ||
    (p.title  || "").toLowerCase().includes(q) ||
    (p.authors || []).join(" ").toLowerCase().includes(q) ||
    (p.journal || "").toLowerCase().includes(q)
  const matchYear = yearFilter === "All years" || p.year === yearFilter
  const matchPer  = !perOnly || p.is_per
  return matchSearch && matchYear && matchPer
})

md`**Showing ${filtered.length} of ${pubs.length} publications** — last updated ${data.last_updated}`

















































Inputs.table(filtered, {
  columns: ["year", "title", "authors", "journal"],
  header: {
    year:    "Year",
    title:   "Title",
    authors: "Authors",
    journal: "Journal"
  },
  format: {
    title: (t, i) =&gt; {
      const pub = filtered[i]
      return pub.url ? htl.html`&lt;a href="${pub.url}" target="_blank"&gt;${t}&lt;/a&gt;` : t
    },
    authors: a =&gt; (a || []).join(", ")
  },
  rows: 20
})

data = await FileAttachment("_data/publications.json").json()
pubs = data.publications

// Build a summary table: one row per author
authorMap = {
  const m = new Map()
  for (const pub of pubs) {
    const authors = pub.authors || []
    const orcids  = pub.orcids  || []
    authors.forEach((name, i) =&gt; {
      if (!m.has(name)) {
        m.set(name, { name, orcid: orcids[i] || "", count: 0, per_count: 0 })
      }
      m.get(name).count++
      if (pub.is_per) m.get(name).per_count++
    })
  }
  return Array.from(m.values()).sort((a, b) =&gt; b.count - a.count)
}

md`**${authorMap.length} authors** contributing **${pubs.length} publications** in total.`




























Inputs.table(authorMap, {
  columns: ["name", "orcid", "count", "per_count"],
  header: {
    name:      "Name",
    orcid:     "ORCID",
    count:     "Total publications",
    per_count: "PER publications"
  },
  format: {
    orcid: id =&gt; id
      ? htl.html`&lt;a href="https://orcid.org/${id}" target="_blank"&gt;${id}&lt;/a&gt;`
      : ""
  }
})
